import React from 'react';

const StatsPanel = ({ totalDonors, filteredDonors }) => {
  return (
    <div className="stats-panel">
      <div className="stat">
        <h3>Total Donors</h3>
        <p>{totalDonors}</p>
      </div>
      <div className="stat">
        <h3>Filtered Donors</h3>
        <p>{filteredDonors}</p>
      </div>
    </div>
  );
};

export default StatsPanel;
